import json
import boto3
import logging
from botocore.exceptions import ClientError

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Set up logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    try:
        # Validate and parse S3 event
        if 'Records' not in event:
            raise ValueError("Invalid event structure")
        
        for record in event['Records']:
            bucket_name = record['s3']['bucket']['name']
            object_key = record['s3']['object']['key']
            
            # Validate bucket and object key
            if not bucket_name or not object_key:
                raise ValueError("Bucket name or object key missing")

            # Process the image
            response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
            image_data = response['Body'].read()
            
            # Placeholder for image processing logic
            processed_data = process_image(image_data)
            
            # Write processed data back to S3
            processed_key = f"processed/{object_key}"
            s3_client.put_object(Bucket=bucket_name, Key=processed_key, Body=processed_data)
            
            # Send notification via SNS
            sns_client.publish(
                TopicArn='arn:aws:sns:us-east-1:123456789012:ImageProcessingTopic',
                Message=f"Image processed and stored at {processed_key}",
                Subject='Image Processing Complete'
            )
            
            logger.info(f"Processed image stored at {processed_key}")

    except ClientError as e:
        logger.error(f"Client error: {e}")
        raise
    except Exception as e:
        logger.error(f"Error processing image: {e}")
        raise

